import Testing
import Foundation
@testable import LXMF
@testable import ReticulumCrypto

// LXMF Compatibility Oracle Tests
//
// Verifies that Swift LXMFMessage produces byte-identical output to the
// Python LXMF reference implementation (tested against lxmf 0.9.4 / rns 1.1.3).
//
// Fixture: Tests/ProtocolFixtures/lxmf/message_basic.json
// Generated by: Tests/Scripts/generate_fixtures.py
//
// Wire format (packed bytes):
//   [destinationHash: 16 bytes]
//   [sourceHash:      16 bytes]
//   [signature:       64 bytes]  Ed25519 over signedPart
//   [msgpackPayload:  variable]  msgpack([timestamp, title, content, fields])
//
// where:
//   messageHash = SHA-256(destinationHash + sourceHash + msgpackPayload)
//   signedPart  = destinationHash + sourceHash + msgpackPayload + messageHash
//
// Tests FAIL until LXMFMessage is fully implemented.

// Helper

private func loadBasicFixture() throws -> [String: Any] {
    try FixtureLoader.load(subdir: "lxmf", name: "message_basic.json")
}

// Envelope Parsing

@Suite("LXMF — Envelope Parsing")
struct LXMFEnvelopeParsingTests {

    @Test("message_basic: parse does not throw")
    func parseDoesNotThrow() throws {
        let fixture = try loadBasicFixture()
        let packed = try fixture.hexData(at: "expected.packed_hex")
        _ = try LXMFMessage(packed: packed)
    }

    @Test("message_basic: packed size is 139 bytes")
    func packedSizeIs139() throws {
        let fixture = try loadBasicFixture()
        let expected = try fixture.int(at: "expected.packed_size")
        let packed = try fixture.hexData(at: "expected.packed_hex")
        #expect(packed.count == expected,
                "Expected packed size \(expected), got \(packed.count)")
    }

    @Test("message_basic: destinationHash is 16 bytes and matches fixture")
    func destinationHashMatchesFixture() throws {
        let fixture = try loadBasicFixture()
        let packed = try fixture.hexData(at: "expected.packed_hex")
        let expected = try fixture.hexData(at: "expected.destination_hash_in_packed_hex")

        let msg = try LXMFMessage(packed: packed)
        #expect(msg.destinationHash.count == 16,
                "destinationHash must be 16 bytes, got \(msg.destinationHash.count)")
        #expect(msg.destinationHash == expected,
                "destinationHash mismatch: expected \(expected.hexString), got \(msg.destinationHash.hexString)")
    }

    @Test("message_basic: sourceHash is 16 bytes and matches fixture")
    func sourceHashMatchesFixture() throws {
        let fixture = try loadBasicFixture()
        let packed = try fixture.hexData(at: "expected.packed_hex")
        let expected = try fixture.hexData(at: "expected.source_hash_in_packed_hex")

        let msg = try LXMFMessage(packed: packed)
        #expect(msg.sourceHash.count == 16,
                "sourceHash must be 16 bytes, got \(msg.sourceHash.count)")
        #expect(msg.sourceHash == expected,
                "sourceHash mismatch: expected \(expected.hexString), got \(msg.sourceHash.hexString)")
    }

    @Test("message_basic: signature is 64 bytes and matches fixture")
    func signatureMatchesFixture() throws {
        let fixture = try loadBasicFixture()
        let packed = try fixture.hexData(at: "expected.packed_hex")
        let expected = try fixture.hexData(at: "expected.signature_in_packed_hex")

        let msg = try LXMFMessage(packed: packed)
        #expect(msg.signature.count == 64,
                "signature must be 64 bytes, got \(msg.signature.count)")
        #expect(msg.signature == expected,
                "signature mismatch: expected \(expected.hexString), got \(msg.signature.hexString)")
    }

    @Test("message_basic: msgpackPayload matches fixture")
    func msgpackPayloadMatchesFixture() throws {
        let fixture = try loadBasicFixture()
        let packed = try fixture.hexData(at: "expected.packed_hex")
        let expected = try fixture.hexData(at: "expected.msgpack_payload_hex")

        let msg = try LXMFMessage(packed: packed)
        #expect(msg.msgpackPayload == expected,
                "msgpackPayload mismatch: expected \(expected.hexString), got \(msg.msgpackPayload.hexString)")
    }
}

