// Message Hash

@Suite("LXMF — Message Hash")
struct LXMFMessageHashTests {

    /// Python: RNS.Identity.full_hash(dest + src + packed_payload) = 32-byte SHA-256
    @Test("message_basic: message hash matches SHA-256(dest+src+payload)")
    func messageHashMatchesFixture() throws {
        let fixture = try loadBasicFixture()
        let packed = try fixture.hexData(at: "expected.packed_hex")
        let expectedHash = try fixture.hexData(at: "expected.message_hash_hex")

        let msg = try LXMFMessage(packed: packed)
        #expect(msg.hash.count == 32,
                "message hash must be 32 bytes (full SHA-256), got \(msg.hash.count)")
        #expect(msg.hash == expectedHash,
                "message hash mismatch: expected \(expectedHash.hexString), got \(msg.hash.hexString)")
    }
}

// Signature Verification

@Suite("LXMF — Signature Verification")
struct LXMFSignatureVerificationTests {

    /// The Ed25519 public key is bytes [32:64] of the RNS identity public key.
    /// Signed data = destinationHash + sourceHash + msgpackPayload + messageHash
    @Test("message_basic: signature verifies with source identity Ed25519 public key")
    func signatureVerifiesWithSourceKey() throws {
        let fixture = try loadBasicFixture()
        let packed = try fixture.hexData(at: "expected.packed_hex")

        // RNS identity public key layout: [0:32] = X25519, [32:64] = Ed25519
        let identityKey = try fixture.hexData(at: "inputs.source_identity_key_hex")
        #expect(identityKey.count == 64,
                "identity public key must be 64 bytes, got \(identityKey.count)")

        let ed25519PublicKey = identityKey.subdata(in: 32..<64)  // bytes [32:64]

        let msg = try LXMFMessage(packed: packed)
        #expect(msg.verifySignature(ed25519PublicKey: ed25519PublicKey),
                "Ed25519 signature verification failed for message_basic fixture")
    }
}

// Round-Trip Serialization

@Suite("LXMF — Serialization")
struct LXMFSerializationTests {

    /// Re-serializes a parsed message and verifies byte-identical output.
    /// This validates both parsing and serialization against Python LXMF.
    @Test("message_basic: pack() produces byte-identical output to Python")
    func packProducesByteIdenticalOutput() throws {
        let fixture = try loadBasicFixture()
        let expectedPacked = try fixture.hexData(at: "expected.packed_hex")

        let msg = try LXMFMessage(packed: expectedPacked)
        let repacked = try msg.pack()

        #expect(repacked == expectedPacked,
                """
                pack() round-trip mismatch:
                  expected: \(expectedPacked.hexString)
                  got:      \(repacked.hexString)
                """)
    }
}

@Suite("LXMF — Stamp Semantics")
struct LXMFStampSemanticsTests {

    @Test("Hash/signature use canonical payload when stamp present")
    func stampedMessageUsesCanonicalHashAndSignature() throws {
        let sender = try Identity.generate()
        let recipient = try Identity.generate()
        let destinationHash = Destination.hash(
            appName: "lxmf",
            aspects: ["delivery"],
            identityHash: recipient.hash
        )

        let packed = try LXMFMessage.create(
            destinationHash: destinationHash,
            sourceIdentity: sender,
            content: "stamp check",
            title: "s",
            timestamp: 1_700_000_100.0,
            stampCost: 6
        )

        let parsed = try LXMFMessage(packed: packed)
        #expect(parsed.stamp != nil)
        #expect(parsed.msgpackPayload != parsed.canonicalMsgpackPayload)
        let senderEd25519 = Data(sender.publicKey[32..<64])
        #expect(parsed.verifySignature(ed25519PublicKey: senderEd25519))
    }

    @Test("Ticket stamp validates and sets ticket cost sentinel")
    func ticketStampValidation() throws {
        let sender = try Identity.generate()
        let recipient = try Identity.generate()
        let destinationHash = Destination.hash(
            appName: "lxmf",
            aspects: ["delivery"],
            identityHash: recipient.hash
        )
        let ticket = Data(repeating: 0xAB, count: 16)

        let packed = try LXMFMessage.create(
            destinationHash: destinationHash,
            sourceIdentity: sender,
            content: "ticket stamp",
            title: "",
            timestamp: 1_700_000_200.0,
            outboundTicket: ticket
        )

        let parsed = try LXMFMessage(packed: packed)
        #expect(parsed.stamp?.count == 16)
        let validation = parsed.validateStamp(targetCost: 10, tickets: [ticket])
        #expect(validation.valid)
        #expect(validation.value == LXMFMessage.ticketStampValue)
    }
}
